// CustomerRestController - Con ResponseEntity
@RestController
@RequestMapping("/api/v1/customer")
public class CustomerRestController {

    @Autowired
    private CustomerService customerService;

    // GET - Retornar lista (200 OK)
    @GetMapping
    public ResponseEntity<List<Customer>> findAll() {
        List<Customer> customers = customerService.findAll();
        return ResponseEntity.ok(customers);  // 200 OK
    }

    // GET - Retornar uno (200 OK)
    @GetMapping("/{id}")
    public ResponseEntity<Customer> findById(@PathVariable Long id) {
        Customer customer = customerService.findById(id);
        return ResponseEntity.ok(customer);  // 200 OK
    }

    // POST - Crear (201 Created)
    @PostMapping
    public ResponseEntity<Customer> create(@RequestBody Customer customer) {
        Customer saved = customerService.create(customer);

        // Opción 1: Simple 201 Created
        return ResponseEntity.status(HttpStatus.CREATED).body(saved);

        // Opción 2: 201 Created con Location header
        // URI location = ServletUriComponentsBuilder
        //     .fromCurrentRequest()
        //     .path("/{id}")
        //     .buildAndExpand(saved.getId())
        //     .toUri();
        // return ResponseEntity.created(location).body(saved);
    }

    // PUT - Actualizar (200 OK)
    @PutMapping("/{id}")
    public ResponseEntity<Customer> update(
            @PathVariable Long id, 
            @RequestBody Customer customer) {
        Customer updated = customerService.update(id, customer);
        return ResponseEntity.ok(updated);  // 200 OK
    }

    // DELETE - Eliminar (204 No Content)
    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable Long id) {
        customerService.delete(id);
        return ResponseEntity.noContent().build();  // 204 No Content
    }
}
